#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // output permutation
        printf("1 %d", N);
        for (int i = 2; i <= N-1; i += 2) {
            printf(" %d %d", i, i+1);
        }
        if (T) printf("\n");
    }
    return 0;
}

