#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> ans;
        ans.reserve(N);
        ans.push_back(1);
        ans.push_back(N);
        for(int i=2;i<=N-1;i+=2){
            ans.push_back(i);
            ans.push_back(i+1);
        }
        for(int i=0;i<N;i++){
            if(i) cout<<' ';
            cout<<ans[i];
        }
        if(T) cout<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            StringBuilder line = new StringBuilder();
            line.append(1).append(' ').append(N);
            for (int i = 2; i <= N - 1; i += 2) {
                line.append(' ').append(i).append(' ').append(i + 1);
            }
            out.append(line);
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        ans = [1, N]
        for i in range(2, N, 2):
            ans.append(i)
            ans.append(i + 1)
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

